def build_google_service(api: str, version: str, scopes: list[str]) -> Any:
    """Build an authenticated Google API client.

    Prefers the OAuth refresh token (required for personal accounts); falls
    back to the service account (Shared Drives / Workspace).
    """
    if settings.GOOGLE_OAUTH_REFRESH_TOKEN:
        creds = Credentials(
            token=None,
            refresh_token=settings.GOOGLE_OAUTH_REFRESH_TOKEN,
            token_uri="https://oauth2.googleapis.com/token",
            client_id=settings.GOOGLE_OAUTH_CLIENT_ID,
            client_secret=settings.GOOGLE_OAUTH_CLIENT_SECRET,
            scopes=scopes,
        )
        creds.refresh(Request())
    else:
        creds = service_account.Credentials.from_service_account_file(
            settings.GOOGLE_SERVICE_ACCOUNT_JSON, scopes=scopes
        )
    return build(api, version, credentials=creds, cache_discovery=False)

def _blob_lines(blobs: list[dict]) -> list[str]:
    """Context blobs (in sort_order)."""
    lines: list[str] = []
    for blob in blobs:
        if blob.get("name"):
            lines += [f"## {blob['name']}", ""]
        content = (blob.get("content") or "").strip()
        if content:
            lines += [content, ""]
    return lines

def _tag_legend_lines(jobs: list[dict], tags: list[dict]) -> list[str]:
    """Tag legend — only tags actually used by jobs in this space."""
    used_tag_ids: set[str] = set()
    for job in jobs:
        for jt in job.get("tags") or []:
            used_tag_ids.add(jt["id"])

    used_tags = [t for t in tags if t["id"] in used_tag_ids]
    if not used_tags:
        return []
    lines = ["## Tag legend", ""]
    for tag in sorted(used_tags, key=lambda t: t["name"]):
        meaning = tag.get("meaning") or ""
        lines.append(f"Name: {tag['name']} meaning: {meaning}")
    lines.append("")
    return lines

async def send_message(
    chat_id: int,
    text: str,
    *,
    reply_to_message_id: int | None = None,
    parse_mode: str | None = None,
) -> dict[str, Any]:
    """Send a plain Telegram message. Returns the parsed `result` field on success."""
    payload: dict[str, Any] = {"chat_id": chat_id, "text": text}
    if reply_to_message_id is not None:
        payload["reply_to_message_id"] = reply_to_message_id
    if parse_mode is not None:
        payload["parse_mode"] = parse_mode
    return await _post_and_parse(
        "sendMessage", json_payload=payload, chat_id=chat_id, parse_mode=parse_mode,
        error_event="telegram_send_failed", success_event="telegram_message_sent",
    )

