    request: Request,
    x_telegram_bot_api_secret_token: str | None = Header(default=None),
) -> dict[str, bool]:
    if not compare_digest(x_telegram_bot_api_secret_token or "", settings.TELEGRAM_WEBHOOK_SECRET):
        log.warning("webhook_invalid_secret")
        raise HTTPException(status_code=403, detail="invalid secret")

    update = await request.json()

    # Handle callback queries (inline keyboard button presses)
    callback = update.get("callback_query")
    if callback:
        await _handle_callback(callback)
        return {"ok": True}

    message = update.get("message") or update.get("edited_message") or {}
    chat = message.get("chat") or {}
    chat_id = chat.get("id")
    text = (message.get("text") or "").strip()
    message_id = message.get("message_id")

    log.info("webhook_received", chat_id=chat_id, message_id=message_id, text_len=len(text))

    # Photo path
    photo = message.get("photo")
    if photo and chat_id:
        await _handle_photo_update(chat_id, message, photo)
        return {"ok": True}

    if not chat_id or not text:
        return {"ok": True}

    await _route_text(chat_id, text, message_id)
    return {"ok": True}

def score_template_match(text: str) -> dict[str, int]:
    """Count keyword hits per template, reading the single trigger-pattern table.

    Templates with no keywords (``summary``) are skipped, so the result keys are
    exactly the routable templates. Shared by ``detect_template`` (auto-routing)
    and ``validate_template_choice`` (mismatch warning) — one table, two readers.
    """
    lowered = text.lower()
    return {
        name: sum(lowered.count(kw) for kw in tmpl.trigger_patterns)
        for name, tmpl in PROMPT_TEMPLATES.items()
        if tmpl.trigger_patterns
    }

def _humanize_age(days: int) -> str:
    """Render a day-count as a human-readable 'X ago' string.

    Examples: 0 → "today", 1 → "yesterday", 3 → "3 days ago",
    240 → "8 months ago", 800 → "2 years ago".
    """
    if days <= 0:
        return "today"
    if days == 1:
        return "yesterday"
    if days < 30:
        return f"{days} days ago"
    if days < 365:
        months = days // 30
        return f"{months} month{'s' if months != 1 else ''} ago"
    years = days // 365
    return f"{years} year{'s' if years != 1 else ''} ago"

